# @cctt_verify {"v":2,"sym":"sympy.integrals.tests.test_integrals.test_is_number","kind":"function","src_hash":"8b7bfd7381c4a334","in":{"base":"Any"},"out":{"base":"Any","pred":"Integral(x).is_number is False and Integral(1, x).is_number is False and Integral(1, (x, 1)).is_number is True and Integral(1, (x, 1, 2)).is_number is True and Integral(1, (x, 1, y)).is_number is False and Integral(1, (x, y)).is_number is False and Integral(x, y).is_number is False and Integral(x, (y, 1, x)).is_number is False and Integral(x, (y, 1, 2)).is_number is False and Integral(x, (x, 1, 2)).is_number is True and i.is_number is False and i.n() == 0 and i.is_number is False and i.n() == 0 and i.is_number is False and i.n() == 2.0 and Integral(x * y, (x, 1, 2), (y, 1, 3)).is_number is True and Integral(x * y, (x, 1, 2), (y, 1, z)).is_number is False and Integral(x, (x, 1)).is_number is True and Integral(x, (x, 1, Integral(y, (y, 1, 2)))).is_number is True and Integral(Sum(z, (z, 1, 2)), (x, 1, 2)).is_number is True and Integral(sin(x) ** 2 + cos(x) ** 2 - 1, x).is_number is False and Integral(f(x), (x, 0, 1)).is_number is True"},"spec":{"lhs":"test_is_number()","rhs":"test_is_number produces the expected output","over":{"base":"Any"},"name":"test_is_number_correct"},"guarantee":"test_is_number produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.integrals.tests.test_integrals.test_is_number_correct","statement":"Path(test_is_number(x), test_is_number produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"7049fdddb63ef8a8"}
def test_is_number():
    from sympy.abc import x, y, z
    assert Integral(x).is_number is False
    assert Integral(1, x).is_number is False
    assert Integral(1, (x, 1)).is_number is True
    assert Integral(1, (x, 1, 2)).is_number is True
    assert Integral(1, (x, 1, y)).is_number is False
    assert Integral(1, (x, y)).is_number is False
    assert Integral(x, y).is_number is False
    assert Integral(x, (y, 1, x)).is_number is False
    assert Integral(x, (y, 1, 2)).is_number is False
    assert Integral(x, (x, 1, 2)).is_number is True
    # `foo.is_number` should always be equivalent to `not foo.free_symbols`
    # in each of these cases, there are pseudo-free symbols
    i = Integral(x, (y, 1, 1))
    assert i.is_number is False and i.n() == 0
    i = Integral(x, (y, z, z))
    assert i.is_number is False and i.n() == 0
    i = Integral(1, (y, z, z + 2))
    assert i.is_number is False and i.n() == 2.0

    assert Integral(x*y, (x, 1, 2), (y, 1, 3)).is_number is True
    assert Integral(x*y, (x, 1, 2), (y, 1, z)).is_number is False
    assert Integral(x, (x, 1)).is_number is True
    assert Integral(x, (x, 1, Integral(y, (y, 1, 2)))).is_number is True
    assert Integral(Sum(z, (z, 1, 2)), (x, 1, 2)).is_number is True
    # it is possible to get a false negative if the integrand is
    # actually an unsimplified zero, but this is true of is_number in general.
    assert Integral(sin(x)**2 + cos(x)**2 - 1, x).is_number is False
    assert Integral(f(x), (x, 0, 1)).is_number is True


