# @cctt_verify {"v":2,"sym":"sympy.integrals.tests.test_integrals.test_issue_5167","kind":"function","src_hash":"a6c6f6a5a1a889d8","in":{"base":"Any"},"out":{"base":"Any","pred":"Integral(Integral(f(x), x), x) == Integral(f(x), x, x) and Integral(f(x)).args == (f(x), Tuple(x)) and Integral(Integral(f(x))).args == (f(x), Tuple(x), Tuple(x)) and Integral(Integral(f(x)), y).args == (f(x), Tuple(x), Tuple(y)) and Integral(Integral(f(x), z), y).args == (f(x), Tuple(z), Tuple(y)) and integrate(Integral(f(x), x), x) == Integral(f(x), x, x) and integrate(Integral(f(x), y), x) == y * Integral(f(x), x) and integrate(Integral(2, x), x) == x ** 2 and integrate(Integral(2, x), y) == 2 * x * y and Integral(1, x, y).args != Integral(1, y, x).args and Integral(f(x), y, x, y, x).doit() == y ** 2 * Integral(f(x), x, x) / 2"},"spec":{"lhs":"test_issue_5167()","rhs":"test_issue_5167 produces the expected output","over":{"base":"Any"},"name":"test_issue_5167_correct"},"guarantee":"test_issue_5167 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.integrals.tests.test_integrals.test_issue_5167_correct","statement":"Path(test_issue_5167(x), test_issue_5167 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"f756a4f5938cc3d6"}
def test_issue_5167():
    from sympy.abc import w, x, y, z
    f = Function('f')
    assert Integral(Integral(f(x), x), x) == Integral(f(x), x, x)
    assert Integral(f(x)).args == (f(x), Tuple(x))
    assert Integral(Integral(f(x))).args == (f(x), Tuple(x), Tuple(x))
    assert Integral(Integral(f(x)), y).args == (f(x), Tuple(x), Tuple(y))
    assert Integral(Integral(f(x), z), y).args == (f(x), Tuple(z), Tuple(y))
    assert Integral(Integral(Integral(f(x), x), y), z).args == \
        (f(x), Tuple(x), Tuple(y), Tuple(z))
    assert integrate(Integral(f(x), x), x) == Integral(f(x), x, x)
    assert integrate(Integral(f(x), y), x) == y*Integral(f(x), x)
    assert integrate(Integral(f(x), x), y) in [Integral(y*f(x), x), y*Integral(f(x), x)]
    assert integrate(Integral(2, x), x) == x**2
    assert integrate(Integral(2, x), y) == 2*x*y
    # don't re-order given limits
    assert Integral(1, x, y).args != Integral(1, y, x).args
    # do as many as possible
    assert Integral(f(x), y, x, y, x).doit() == y**2*Integral(f(x), x, x)/2
    assert Integral(f(x), (x, 1, 2), (w, 1, x), (z, 1, y)).doit() == \
        y*(x - 1)*Integral(f(x), (x, 1, 2)) - (x - 1)*Integral(f(x), (x, 1, 2))


