# @cctt_verify {"v":2,"sym":"sympy.integrals.tests.test_integrals.test_issue_20782","kind":"function","src_hash":"a7857f5a338225bc","in":{"base":"Any"},"out":{"base":"Any","pred":"integrate(fun1, L) == 1 and integrate(fun2, L) == 0 and integrate(-fun1, L) == -1 and integrate(-fun2, L) == 0 and integrate(fun_sum, L) == 1.0 and integrate(-fun_sum, L) == -1.0"},"spec":{"lhs":"test_issue_20782()","rhs":"test_issue_20782 produces the expected output","over":{"base":"Any"},"name":"test_issue_20782_correct"},"guarantee":"test_issue_20782 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.integrals.tests.test_integrals.test_issue_20782_correct","statement":"Path(test_issue_20782(x), test_issue_20782 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"c2cea4b0983911b8"}
def test_issue_20782():
    fun1 = Piecewise((0, x < 0.0), (1, True))
    fun2 = -Piecewise((0, x < 1.0), (1, True))
    fun_sum = fun1 + fun2
    L = (x, -float('Inf'), 1)

    assert integrate(fun1, L) == 1
    assert integrate(fun2, L) == 0
    assert integrate(-fun1, L) == -1
    assert integrate(-fun2, L) == 0
    assert integrate(fun_sum, L) == 1.
    assert integrate(-fun_sum, L) == -1.


