# @cctt_verify {"v":2,"sym":"sympy.integrals.tests.test_integrals.test_issue_20781","kind":"function","src_hash":"4dafb2b222259d87","in":{"base":"Any"},"out":{"base":"Any","pred":"f1 == 2 * x - Min(1.0, x) - Min(x, Max(1.0, 1, evaluate=False)) and integrate(f(0), (x, -float('Inf'), x)) == 2 * x - 2 * Min(0, x)"},"spec":{"lhs":"test_issue_20781()","rhs":"test_issue_20781 produces the expected output","over":{"base":"Any"},"name":"test_issue_20781_correct"},"guarantee":"test_issue_20781 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.integrals.tests.test_integrals.test_issue_20781_correct","statement":"Path(test_issue_20781(x), test_issue_20781 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"06d2a65b2ee8984d"}
def test_issue_20781():
    P = lambda a: Piecewise((0, x < a), (1, x >= a))
    f = lambda a: P(int(a)) + P(float(a))
    L = (x, -float('Inf'), x)
    f1 = integrate(f(1), L)
    assert f1 == 2*x - Min(1.0, x) - Min(x, Max(1.0, 1, evaluate=False))
    # XXX is_zero is True for S(0) and Float(0) and this is baked into
    # the code more deeply than the issue of Float(0) != S(0)
    assert integrate(f(0), (x, -float('Inf'), x)
        ) == 2*x - 2*Min(0, x)


