# @cctt_verify {"v":2,"sym":"sympy.integrals.tests.test_integrals.test_old_issues","kind":"function","src_hash":"e19057c70731788d","in":{"base":"Any"},"out":{"base":"Any","pred":"I1 == sin(log(x ** 2)) / 2 and I2 == x / (y ** 3 * sqrt(x ** 2 / y ** 2 + 1)) and I3 == 2 * sqrt(3) * pi / 3"},"spec":{"lhs":"test_old_issues()","rhs":"test_old_issues produces the expected output","over":{"base":"Any"},"name":"test_old_issues_correct"},"guarantee":"test_old_issues produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.integrals.tests.test_integrals.test_old_issues_correct","statement":"Path(test_old_issues(x), test_old_issues produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"3f90a245e096183e"}
def test_old_issues():
    # https://github.com/sympy/sympy/issues/5212
    I1 = integrate(cos(log(x**2))/x)
    assert I1 == sin(log(x**2))/2
    # https://github.com/sympy/sympy/issues/5462
    I2 = integrate(1/(x**2+y**2)**(Rational(3,2)),x)
    assert I2 == x/(y**3*sqrt(x**2/y**2 + 1))
    # https://github.com/sympy/sympy/issues/6278
    I3 = integrate(1/(cos(x)+2),(x,0,2*pi))
    assert I3 == 2*sqrt(3)*pi/3


