# @cctt_verify {"v":2,"sym":"sympy.integrals.tests.test_integrals.test_integral_issue_26566","kind":"function","src_hash":"4637a75972278aa6","in":{"base":"Any"},"out":{"base":"Any","pred":"simplify(numeric_symbolic_result - numeric_correct_result) == 0"},"spec":{"lhs":"test_integral_issue_26566()","rhs":"test_integral_issue_26566 produces the expected output","over":{"base":"Any"},"name":"test_integral_issue_26566_correct"},"guarantee":"test_integral_issue_26566 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.integrals.tests.test_integrals.test_integral_issue_26566_correct","statement":"Path(test_integral_issue_26566(x), test_integral_issue_26566 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"d9b3bc2925ad8f63"}
def test_integral_issue_26566():
    # Define the symbols
    x = symbols('x', real=True)
    a = symbols('a', real=True, positive=True)

    # Define the integral expression
    integral_expr = sin(a * (x + pi))**2
    symbolic_result = integrate(integral_expr, (x, -pi, -pi/2))

    # Known correct result
    correct_result = pi / 4

    # Substitute a specific value for 'a' to evaluate both results
    a_value = 1
    numeric_symbolic_result = symbolic_result.subs(a, a_value).evalf()
    numeric_correct_result = correct_result.evalf()

    # Assert that the symbolic result matches the correct value
    assert simplify(numeric_symbolic_result - numeric_correct_result) == 0


